T = readtable('wheelConvexHull.CSV', 'Delimiter', ',', 'ReadVariableNames', true); %[output:5d1a0166]
coordStr = T{:, end};   % cell array of strings

P = zeros(numel(coordStr), 3);

scale = 1e-3;

for i = 1:numel(coordStr)
    vals = sscanf(coordStr{i}, '%f, %f, %f');
    P(i,:) = scale*vals';
end

size(P) %[output:0275b498]

scatter3(P(:,1), P(:,2), P(:,3), '.') %[output:2c7be8f5]
axis equal %[output:2c7be8f5]
K = convhull(P(:,1), P(:,2), P(:,3));
P_hull = unique(P(K(:),:), 'rows');

trisurf(K, P(:,1), P(:,2), P(:,3), ... %[output:5a9ea7aa]
    'FaceAlpha',0.1,'EdgeColor','k') %[output:5a9ea7aa]
axis equal %[output:5a9ea7aa]
%[text] Spherical proxy
r = sqrt(sum(P_hull.^2,2));
R_sphere = max(r) %[output:7d87e240]

z_min = min(P_hull(:,3));
z_max = max(P_hull(:,3));

z_center = (z_max + z_min)/2;
dz = - z_center %[output:2ef83660]
%[text] Create a disk proxy
% P_hull: Nx3 point cloud of one wheel
% Assumption:
%   - wheel axis is y
%   - rolling plane is x-z
% Units:
%   - output has same units as P_hull

P = P_hull;

% Width direction
ymin = min(P(:,2));
ymax = max(P(:,2));
W = ymax - ymin;

% Split into three equal width bands
y1 = ymin + W/3;
y2 = ymin + 2*W/3;

idx_side_1 = P(:,2) >= ymin & P(:,2) <  y1;
idx_mid    = P(:,2) >= y1   & P(:,2) <= y2;
idx_side_2 = P(:,2) >  y2   & P(:,2) <= ymax;

% Radii in rolling plane
r1 = sqrt(P(idx_side_1,1).^2 + P(idx_side_1,3).^2);
rm = sqrt(P(idx_mid,1).^2    + P(idx_mid,3).^2);
r2 = sqrt(P(idx_side_2,1).^2 + P(idx_side_2,3).^2);

% Robust radii (avoid single-point outliers)
R_mid   = prctile(rm,95);
R_side1 = prctile(r1,95);
R_side2 = prctile(r2,95);

% Enforce left-right symmetry for the side cylinders
R_side = 0.5*(R_side1 + R_side2);

% Offsets of side-cylinder centers with respect to the mid-cylinder center
Y_mid   = 0.5*(y1 + y2);
Y_side1 = 0.5*(ymin + y1);
Y_side2 = 0.5*(y2 + ymax);

dY_side1 = Y_side1 - Y_mid;
dY_side2 = Y_side2 - Y_mid;

% Radius offsets with respect to the mid cylinder
dR_side = R_side - R_mid;

% Display
fprintf('Mid cylinder radius         = %.6f\n', R_mid); %[output:0f998f8e]
fprintf('Side cylinder radius        = %.6f\n', R_side); %[output:9cc6a8c0]
fprintf('Side radius offset dR       = %.6f\n', dR_side); %[output:3e5d2242]
fprintf('Side 1 center offset dY     = %.6f\n', dY_side1); %[output:46b04f70]
fprintf('Side 2 center offset dY     = %.6f\n', dY_side2); %[output:84dc88bc]




